import * as React from "react"
import { cn } from "@/lib/utils"
import { Input } from "@/components/ui/input"

interface AddonInputProps extends React.ComponentProps<typeof Input> {
  prefix?: React.ReactNode
  suffix?: React.ReactNode
  containerClassName?: string
}

const AddonInput = React.forwardRef<HTMLInputElement, AddonInputProps>(
  ({ className, prefix, suffix, containerClassName, ...props }, ref) => {
    return (
      <div
        className={cn(
          "group flex items-center rounded-(--radius) border border-border bg-input transition-all focus-within:ring-2 focus-within:ring-ring",
          containerClassName
        )}
      >
        {prefix && (
          <div className="flex h-full items-center justify-center pl-3 text-muted-foreground">
            {prefix}
          </div>
        )}
        <Input
          ref={ref}
          className={cn(
            "border-0 bg-transparent py-0 shadow-none ring-0 focus-visible:ring-0",
            className
          )}
          {...props}
        />
        {suffix && (
          <div className="flex h-full items-center justify-center pr-3 text-muted-foreground">
            {suffix}
          </div>
        )}
      </div>
    )
  }
)
AddonInput.displayName = "AddonInput"

export { AddonInput }
